import{_ as o,o as d,c as t,ae as a}from"./chunks/framework.BEtfQoF7.js";const u=JSON.parse('{"title":"VS Code에서 Claude Code 사용하기","description":"VS Code용 Claude Code 확장 프로그램을 설치하고 설정하세요. 인라인 diff, @-멘션, 플랜 검토, 키보드 단축키로 AI 코딩 지원을 받을 수 있습니다.","frontmatter":{"title":"VS Code에서 Claude Code 사용하기","description":"VS Code용 Claude Code 확장 프로그램을 설치하고 설정하세요. 인라인 diff, @-멘션, 플랜 검토, 키보드 단축키로 AI 코딩 지원을 받을 수 있습니다."},"headers":[],"relativePath":"vs-code.md","filePath":"vs-code.md","lastUpdated":1776205703000}'),l={name:"vs-code.md"};function s(c,e,i,r,n,p){return d(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="vs-code에서-claude-code-사용하기" tabindex="-1">VS Code에서 Claude Code 사용하기 <a class="header-anchor" href="#vs-code에서-claude-code-사용하기" aria-label="Permalink to &quot;VS Code에서 Claude Code 사용하기&quot;">​</a></h1><img src="https://mintcdn.com/claude-code/-YhHHmtSxwr7W8gy/images/vs-code-extension-interface.jpg?fit=max&amp;auto=format&amp;n=-YhHHmtSxwr7W8gy&amp;q=85&amp;s=300652d5678c63905e6b0ea9e50835f8" alt="오른쪽에 Claude Code 확장 프로그램 패널이 열려 있는 VS Code 편집기, Claude와의 대화 표시" width="2500" height="1155" data-path="images/vs-code-extension-interface.jpg"><p>VS Code 확장 프로그램은 IDE에 직접 통합된 Claude Code의 기본 그래픽 인터페이스를 제공합니다. 이것이 VS Code에서 Claude Code를 사용하는 권장 방법입니다.</p><p>확장 프로그램을 사용하면 Claude의 플랜을 수락하기 전에 검토하고 편집하거나, 편집 사항을 자동으로 수락하거나, 선택 영역에서 특정 줄 범위로 파일을 @-멘션하거나, 대화 기록에 액세스하거나, 별도의 탭이나 창에서 여러 대화를 열 수 있습니다.</p><h2 id="사전-요구-사항" tabindex="-1">사전 요구 사항 <a class="header-anchor" href="#사전-요구-사항" aria-label="Permalink to &quot;사전 요구 사항&quot;">​</a></h2><p>설치하기 전에 다음을 확인하세요:</p><ul><li>VS Code 1.98.0 이상</li><li>Anthropic 계정 (확장 프로그램을 처음 열 때 로그인). Amazon Bedrock이나 Google Vertex AI와 같은 서드파티 공급자를 사용하는 경우 <a href="#서드파티-공급자-사용">서드파티 공급자 사용</a>을 대신 참조하세요.</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>확장 프로그램에는 CLI(명령줄 인터페이스)가 포함되어 있으며, 고급 기능을 위해 VS Code의 통합 터미널에서 액세스할 수 있습니다. 자세한 내용은 <a href="#vs-code-확장-프로그램-vs-claude-code-cli">VS Code 확장 프로그램 vs. Claude Code CLI</a>를 참조하세요.</p></div><h2 id="확장-프로그램-설치" tabindex="-1">확장 프로그램 설치 <a class="header-anchor" href="#확장-프로그램-설치" aria-label="Permalink to &quot;확장 프로그램 설치&quot;">​</a></h2><p>IDE 링크를 클릭하여 바로 설치하세요:</p><ul><li><a href="vscode:extension/anthropic.claude-code" target="_blank" rel="noreferrer">VS Code용 설치</a></li><li><a href="cursor:extension/anthropic.claude-code" target="_blank" rel="noreferrer">Cursor용 설치</a></li></ul><p>또는 VS Code에서 <code>Cmd+Shift+X</code> (Mac) 또는 <code>Ctrl+Shift+X</code> (Windows/Linux)를 눌러 확장 프로그램 보기를 열고, &quot;Claude Code&quot;를 검색한 다음 <strong>설치</strong>를 클릭하세요.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>설치 후 확장 프로그램이 나타나지 않으면 VS Code를 다시 시작하거나 Command Palette에서 &quot;Developer: Reload Window&quot;를 실행하세요.</p></div><h2 id="시작하기" tabindex="-1">시작하기 <a class="header-anchor" href="#시작하기" aria-label="Permalink to &quot;시작하기&quot;">​</a></h2><p>설치 후 VS Code 인터페이스를 통해 Claude Code를 사용할 수 있습니다:</p><p><strong>1단계: Claude Code 패널 열기</strong></p><p>VS Code 전반에 걸쳐 Spark 아이콘이 Claude Code를 나타냅니다: <img src="https://mintcdn.com/claude-code/c5r9_6tjPMzFdDDT/images/vs-code-spark-icon.svg?fit=max&amp;auto=format&amp;n=c5r9_6tjPMzFdDDT&amp;q=85&amp;s=3ca45e00deadec8c8f4b4f807da94505" alt="Spark 아이콘" style="display:inline;height:0.85em;vertical-align:middle;" width="16" height="16" data-path="images/vs-code-spark-icon.svg"></p><p>Claude를 여는 가장 빠른 방법은 <strong>편집기 도구 모음</strong>(편집기 오른쪽 상단)의 Spark 아이콘을 클릭하는 것입니다. 이 아이콘은 파일이 열려 있을 때만 나타납니다.</p><img src="https://mintcdn.com/claude-code/mfM-EyoZGnQv8JTc/images/vs-code-editor-icon.png?fit=max&amp;auto=format&amp;n=mfM-EyoZGnQv8JTc&amp;q=85&amp;s=eb4540325d94664c51776dbbfec4cf02" alt="편집기 도구 모음에 Spark 아이콘이 표시된 VS Code 편집기" width="2796" height="734" data-path="images/vs-code-editor-icon.png"><p>Claude Code를 여는 다른 방법:</p><ul><li><strong>Activity Bar</strong>: 왼쪽 사이드바의 Spark 아이콘을 클릭하여 세션 목록을 엽니다. 세션을 클릭하면 전체 편집기 탭으로 열리거나 새로 시작할 수 있습니다. 이 아이콘은 Activity Bar에서 항상 표시됩니다.</li><li><strong>Command Palette</strong>: <code>Cmd+Shift+P</code> (Mac) 또는 <code>Ctrl+Shift+P</code> (Windows/Linux), &quot;Claude Code&quot;를 입력하고 &quot;Open in New Tab&quot;과 같은 옵션을 선택합니다.</li><li><strong>Status Bar</strong>: 창의 오른쪽 하단에서 <strong>✱ Claude Code</strong>를 클릭합니다. 파일이 열려 있지 않을 때도 작동합니다.</li></ul><p>Claude 패널을 드래그하여 VS Code 어디에나 재배치할 수 있습니다. 자세한 내용은 <a href="#워크플로우-사용자-정의">워크플로우 사용자 정의</a>를 참조하세요.</p><p><strong>2단계: 로그인</strong></p><p>처음 패널을 열면 로그인 화면이 나타납니다. <strong>로그인</strong>을 클릭하고 브라우저에서 인증을 완료하세요.</p><p>나중에 <strong>Not logged in · Please run /login</strong>이 표시되면 확장 프로그램이 자동으로 로그인 화면을 다시 엽니다. 나타나지 않으면 Command Palette에서 <strong>Developer: Reload Window</strong>로 창을 다시 로드하세요.</p><p>셸에 <code>ANTHROPIC_API_KEY</code>가 설정되어 있지만 로그인 프롬프트가 계속 표시되면 VS Code가 셸 환경을 상속하지 않았을 수 있습니다. <code>code .</code>로 터미널에서 VS Code를 실행하여 환경 변수를 상속받거나, Claude 계정으로 로그인하세요.</p><p>로그인 후 <strong>Learn Claude Code</strong> 체크리스트가 나타납니다. <strong>Show me</strong>를 클릭하여 각 항목을 진행하거나 X로 닫으세요. 나중에 다시 열려면 VS Code 설정의 Extensions → Claude Code에서 <strong>Hide Onboarding</strong> 체크를 해제하세요.</p><p><strong>3단계: 프롬프트 전송</strong></p><p>코드나 파일에 대해 Claude에게 도움을 요청하세요. 작동 방식 설명, 문제 디버깅, 변경 사항 적용 등을 물어볼 수 있습니다.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Claude는 선택한 텍스트를 자동으로 봅니다. <code>Option+K</code> (Mac) / <code>Alt+K</code> (Windows/Linux)를 눌러 프롬프트에 @-멘션 참조(예: <code>@file.ts#5-10</code>)를 삽입할 수도 있습니다.</p></div><p>파일의 특정 줄에 대해 질문하는 예시:</p><img src="https://mintcdn.com/claude-code/FVYz38sRY-VuoGHA/images/vs-code-send-prompt.png?fit=max&amp;auto=format&amp;n=FVYz38sRY-VuoGHA&amp;q=85&amp;s=ede3ed8d8d5f940e01c5de636d009cfd" alt="Python 파일에서 2-3번째 줄이 선택된 VS Code 편집기와 @-멘션 참조를 사용하여 해당 줄에 대한 질문이 표시된 Claude Code 패널" width="3288" height="1876" data-path="images/vs-code-send-prompt.png"><p><strong>4단계: 변경 사항 검토</strong></p><p>Claude가 파일을 편집하려고 할 때, 원본과 제안된 변경 사항을 나란히 비교하여 보여주고 권한을 요청합니다. 수락, 거부 또는 Claude에게 다른 방향을 제시할 수 있습니다.</p><img src="https://mintcdn.com/claude-code/FVYz38sRY-VuoGHA/images/vs-code-edits.png?fit=max&amp;auto=format&amp;n=FVYz38sRY-VuoGHA&amp;q=85&amp;s=e005f9b41c541c5c7c59c082f7c4841c" alt="편집을 할지 묻는 권한 프롬프트와 함께 Claude의 제안된 변경 사항의 diff가 표시된 VS Code" width="3292" height="1876" data-path="images/vs-code-edits.png"><p>Claude Code로 할 수 있는 더 많은 아이디어는 <a href="/claude-code-docs-ko/common-workflows.html">일반 워크플로우</a>를 참조하세요.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Command Palette에서 &quot;Claude Code: Open Walkthrough&quot;를 실행하여 기본 사항에 대한 가이드 투어를 받을 수 있습니다.</p></div><h2 id="프롬프트-박스-사용" tabindex="-1">프롬프트 박스 사용 <a class="header-anchor" href="#프롬프트-박스-사용" aria-label="Permalink to &quot;프롬프트 박스 사용&quot;">​</a></h2><p>프롬프트 박스는 여러 기능을 지원합니다:</p><ul><li><strong>권한 모드</strong>: 프롬프트 박스 하단의 모드 표시기를 클릭하여 모드를 전환합니다. 일반 모드에서는 Claude가 각 작업 전에 권한을 요청합니다. Plan 모드에서는 Claude가 수행할 내용을 설명하고 변경하기 전에 승인을 기다립니다. VS Code는 Claude가 시작하기 전에 피드백을 제공할 수 있도록 플랜을 전체 마크다운 문서로 자동으로 엽니다. 자동 수락 모드에서는 Claude가 묻지 않고 편집합니다. VS Code 설정의 <code>claudeCode.initialPermissionMode</code>에서 기본값을 설정할 수 있습니다.</li><li><strong>명령 메뉴</strong>: <code>/</code>를 클릭하거나 <code>/</code>를 입력하여 명령 메뉴를 엽니다. 파일 첨부, 모델 전환, 확장 사고 토글, 플랜 사용량 보기(<code>/usage</code>), <a href="/claude-code-docs-ko/remote-control.html">원격 제어</a> 세션 시작(<code>/remote-control</code>) 등의 옵션이 있습니다. Customize 섹션에서 MCP 서버, 훅, 메모리, 권한, 플러그인에 액세스할 수 있습니다. 터미널 아이콘이 있는 항목은 통합 터미널에서 열립니다.</li><li><strong>컨텍스트 표시기</strong>: 프롬프트 박스는 Claude의 컨텍스트 창을 얼마나 사용하고 있는지 보여줍니다. 필요할 때 Claude가 자동으로 압축하거나, <code>/compact</code>를 수동으로 실행할 수 있습니다.</li><li><strong>확장 사고</strong>: Claude가 복잡한 문제를 더 많은 시간을 들여 추론할 수 있게 합니다. 명령 메뉴(<code>/</code>)를 통해 켜세요. 자세한 내용은 <a href="/claude-code-docs-ko/common-workflows.html#use-extended-thinking-thinking-mode">확장 사고</a>를 참조하세요.</li><li><strong>여러 줄 입력</strong>: 전송하지 않고 새 줄을 추가하려면 <code>Shift+Enter</code>를 누르세요. 질문 대화 상자의 &quot;Other&quot; 자유 텍스트 입력에서도 작동합니다.</li></ul><h3 id="파일-및-폴더-참조" tabindex="-1">파일 및 폴더 참조 <a class="header-anchor" href="#파일-및-폴더-참조" aria-label="Permalink to &quot;파일 및 폴더 참조&quot;">​</a></h3><p>@-멘션을 사용하여 특정 파일이나 폴더에 대한 컨텍스트를 Claude에게 제공하세요. <code>@</code> 다음에 파일이나 폴더 이름을 입력하면 Claude가 해당 내용을 읽고 질문에 답하거나 변경할 수 있습니다. Claude Code는 퍼지 매칭을 지원하므로 부분 이름을 입력하여 원하는 항목을 찾을 수 있습니다:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt; Explain the logic in @auth (fuzzy matches auth.js, AuthService.ts, etc.)</span></span>\n<span class="line"><span>&gt; What&#39;s in @src/components/ (include a trailing slash for folders)</span></span></code></pre></div><p>대용량 PDF의 경우 전체 파일 대신 특정 페이지를 읽도록 Claude에게 요청할 수 있습니다. 단일 페이지, 1-10페이지와 같은 범위, 또는 3페이지부터와 같은 개방형 범위를 지정할 수 있습니다.</p><p>편집기에서 텍스트를 선택하면 Claude가 강조 표시된 코드를 자동으로 볼 수 있습니다. 프롬프트 박스 하단에 선택된 줄 수가 표시됩니다. <code>Option+K</code> (Mac) / <code>Alt+K</code> (Windows/Linux)를 눌러 파일 경로와 줄 번호가 포함된 @-멘션(예: <code>@app.ts#5-10</code>)을 삽입하세요. 선택 표시기를 클릭하여 Claude가 강조 표시된 텍스트를 볼 수 있는지 토글합니다. 눈-슬래시 아이콘은 선택 영역이 Claude에게 숨겨져 있음을 의미합니다.</p><p><code>Shift</code>를 누른 채로 파일을 프롬프트 박스로 드래그하여 첨부 파일로 추가할 수도 있습니다. 첨부 파일의 X를 클릭하면 컨텍스트에서 제거됩니다.</p><h3 id="이전-대화-재개" tabindex="-1">이전 대화 재개 <a class="header-anchor" href="#이전-대화-재개" aria-label="Permalink to &quot;이전 대화 재개&quot;">​</a></h3><p>Claude Code 패널 상단의 드롭다운을 클릭하여 대화 기록에 액세스하세요. 키워드로 검색하거나 시간별(오늘, 어제, 최근 7일 등)로 탐색할 수 있습니다. 대화를 클릭하면 전체 메시지 기록과 함께 재개됩니다. 새 세션은 첫 번째 메시지를 기반으로 AI가 생성한 제목을 받습니다. 세션 위에 마우스를 올리면 이름 변경 및 제거 작업이 표시됩니다. 이름을 변경하여 설명적인 제목을 부여하거나, 제거하여 목록에서 삭제하세요. 세션 재개에 대한 자세한 내용은 <a href="/claude-code-docs-ko/common-workflows.html#resume-previous-conversations">일반 워크플로우</a>를 참조하세요.</p><h3 id="claude-ai의-원격-세션-재개" tabindex="-1">Claude.ai의 원격 세션 재개 <a class="header-anchor" href="#claude-ai의-원격-세션-재개" aria-label="Permalink to &quot;Claude.ai의 원격 세션 재개&quot;">​</a></h3><p><a href="/claude-code-docs-ko/claude-code-on-the-web.html">웹에서 Claude Code</a>를 사용하는 경우 VS Code에서 직접 해당 원격 세션을 재개할 수 있습니다. 이 기능은 Anthropic Console이 아닌 <strong>Claude.ai 구독</strong>으로 로그인해야 합니다.</p><p><strong>1단계: 과거 대화 열기</strong></p><p>Claude Code 패널 상단의 <strong>Past Conversations</strong> 드롭다운을 클릭합니다.</p><p><strong>2단계: Remote 탭 선택</strong></p><p>대화 상자에는 Local과 Remote 두 탭이 표시됩니다. <strong>Remote</strong>를 클릭하여 claude.ai의 세션을 확인합니다.</p><p><strong>3단계: 재개할 세션 선택</strong></p><p>원격 세션을 탐색하거나 검색합니다. 세션을 클릭하면 다운로드되어 로컬에서 대화를 계속할 수 있습니다.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>GitHub 저장소로 시작한 웹 세션만 Remote 탭에 표시됩니다. 재개하면 대화 기록이 로컬로 로드되며 변경 사항은 claude.ai에 다시 동기화되지 않습니다.</p></div><h2 id="워크플로우-사용자-정의" tabindex="-1">워크플로우 사용자 정의 <a class="header-anchor" href="#워크플로우-사용자-정의" aria-label="Permalink to &quot;워크플로우 사용자 정의&quot;">​</a></h2><p>설정이 완료되면 Claude 패널을 재배치하거나, 여러 세션을 실행하거나, 터미널 모드로 전환할 수 있습니다.</p><h3 id="claude-위치-선택" tabindex="-1">Claude 위치 선택 <a class="header-anchor" href="#claude-위치-선택" aria-label="Permalink to &quot;Claude 위치 선택&quot;">​</a></h3><p>Claude 패널을 드래그하여 VS Code 어디에나 재배치할 수 있습니다. 패널의 탭이나 제목 표시줄을 잡고 드래그하세요:</p><ul><li><strong>보조 사이드바</strong>: 창의 오른쪽. 코딩하는 동안 Claude를 계속 볼 수 있습니다.</li><li><strong>기본 사이드바</strong>: Explorer, Search 등의 아이콘이 있는 왼쪽 사이드바.</li><li><strong>편집기 영역</strong>: 파일 옆에 탭으로 Claude를 엽니다. 부가 작업에 유용합니다.</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>주요 Claude 세션에는 사이드바를 사용하고 부가 작업에는 추가 탭을 여세요. Claude가 선호하는 위치를 기억합니다. Activity Bar 세션 목록 아이콘은 Claude 패널과 별개입니다. 세션 목록은 Activity Bar에 항상 표시되지만, Claude 패널 아이콘은 패널이 왼쪽 사이드바에 도킹된 경우에만 표시됩니다.</p></div><h3 id="여러-대화-실행" tabindex="-1">여러 대화 실행 <a class="header-anchor" href="#여러-대화-실행" aria-label="Permalink to &quot;여러 대화 실행&quot;">​</a></h3><p>Command Palette에서 <strong>Open in New Tab</strong> 또는 <strong>Open in New Window</strong>를 사용하여 추가 대화를 시작하세요. 각 대화는 자체 기록과 컨텍스트를 유지하여 다른 작업을 병렬로 처리할 수 있습니다.</p><p>탭을 사용할 때, spark 아이콘의 작은 색상 점이 상태를 나타냅니다. 파란색은 권한 요청이 대기 중임을, 주황색은 탭이 숨겨진 동안 Claude가 완료되었음을 의미합니다.</p><h3 id="터미널-모드로-전환" tabindex="-1">터미널 모드로 전환 <a class="header-anchor" href="#터미널-모드로-전환" aria-label="Permalink to &quot;터미널 모드로 전환&quot;">​</a></h3><p>기본적으로 확장 프로그램은 그래픽 채팅 패널을 엽니다. CLI 스타일 인터페이스를 선호하는 경우 <a href="vscode://settings/claudeCode.useTerminal" target="_blank" rel="noreferrer">Use Terminal 설정</a>을 열고 체크박스를 선택하세요.</p><p>VS Code 설정(<code>Cmd+,</code> Mac 또는 <code>Ctrl+,</code> Windows/Linux)을 열고 Extensions → Claude Code로 이동하여 <strong>Use Terminal</strong>을 체크할 수도 있습니다.</p><h2 id="플러그인-관리" tabindex="-1">플러그인 관리 <a class="header-anchor" href="#플러그인-관리" aria-label="Permalink to &quot;플러그인 관리&quot;">​</a></h2><p>VS Code 확장 프로그램에는 <a href="/claude-code-docs-ko/plugins.html">플러그인</a> 설치 및 관리를 위한 그래픽 인터페이스가 포함되어 있습니다. 프롬프트 박스에 <code>/plugins</code>를 입력하여 <strong>플러그인 관리</strong> 인터페이스를 엽니다.</p><h3 id="플러그인-설치" tabindex="-1">플러그인 설치 <a class="header-anchor" href="#플러그인-설치" aria-label="Permalink to &quot;플러그인 설치&quot;">​</a></h3><p>플러그인 대화 상자에는 <strong>Plugins</strong>와 <strong>Marketplaces</strong> 두 탭이 있습니다.</p><p>Plugins 탭에서:</p><ul><li><strong>설치된 플러그인</strong>은 상단에 활성화/비활성화 토글 스위치와 함께 표시됩니다</li><li>구성된 마켓플레이스의 <strong>사용 가능한 플러그인</strong>이 아래에 표시됩니다</li><li>이름이나 설명으로 플러그인을 필터링하여 검색합니다</li><li>사용 가능한 플러그인에서 <strong>Install</strong>을 클릭합니다</li></ul><p>플러그인을 설치할 때 설치 범위를 선택하세요:</p><ul><li><strong>나를 위해 설치</strong>: 모든 프로젝트에서 사용 가능 (사용자 범위)</li><li><strong>이 프로젝트를 위해 설치</strong>: 프로젝트 협력자와 공유 (프로젝트 범위)</li><li><strong>로컬에 설치</strong>: 이 저장소에서만, 나만 사용 (로컬 범위)</li></ul><h3 id="마켓플레이스-관리" tabindex="-1">마켓플레이스 관리 <a class="header-anchor" href="#마켓플레이스-관리" aria-label="Permalink to &quot;마켓플레이스 관리&quot;">​</a></h3><p><strong>Marketplaces</strong> 탭으로 전환하여 플러그인 소스를 추가하거나 제거하세요:</p><ul><li>GitHub 저장소, URL 또는 로컬 경로를 입력하여 새 마켓플레이스를 추가합니다</li><li>새로 고침 아이콘을 클릭하여 마켓플레이스의 플러그인 목록을 업데이트합니다</li><li>휴지통 아이콘을 클릭하여 마켓플레이스를 제거합니다</li></ul><p>변경 사항을 적용하면 배너가 나타나 Claude Code를 다시 시작하라는 메시지가 표시됩니다.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>VS Code의 플러그인 관리는 내부적으로 동일한 CLI 명령을 사용합니다. 확장 프로그램에서 구성한 플러그인과 마켓플레이스는 CLI에서도 사용할 수 있으며, 그 반대도 마찬가지입니다.</p></div><p>플러그인 시스템에 대한 자세한 내용은 <a href="/claude-code-docs-ko/plugins.html">플러그인</a> 및 <a href="/claude-code-docs-ko/plugin-marketplaces.html">플러그인 마켓플레이스</a>를 참조하세요.</p><h2 id="chrome으로-브라우저-작업-자동화" tabindex="-1">Chrome으로 브라우저 작업 자동화 <a class="header-anchor" href="#chrome으로-브라우저-작업-자동화" aria-label="Permalink to &quot;Chrome으로 브라우저 작업 자동화&quot;">​</a></h2><p>Claude를 Chrome 브라우저에 연결하여 웹 앱을 테스트하고, 콘솔 로그로 디버깅하고, VS Code를 떠나지 않고 브라우저 워크플로우를 자동화하세요. 이 기능은 <a href="https://chromewebstore.google.com/detail/claude/fcoeoabgfenejglbffodgkkbkcdhcgfn" target="_blank" rel="noreferrer">Claude in Chrome 확장 프로그램</a> 버전 1.0.36 이상이 필요합니다.</p><p>프롬프트 박스에 <code>@browser</code>를 입력하고 Claude에게 수행하려는 작업을 입력하세요:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>@browser go to localhost:3000 and check the console for errors</span></span></code></pre></div><p>첨부 파일 메뉴를 열어 새 탭 열기나 페이지 콘텐츠 읽기와 같은 특정 브라우저 도구를 선택할 수도 있습니다.</p><p>Claude는 브라우저 작업을 위해 새 탭을 열고 브라우저의 로그인 상태를 공유하므로, 이미 로그인한 모든 사이트에 액세스할 수 있습니다.</p><p>설정 지침, 전체 기능 목록 및 문제 해결을 위해서는 <a href="/claude-code-docs-ko/chrome.html">Chrome과 함께 Claude Code 사용하기</a>를 참조하세요.</p><h2 id="vs-code-명령-및-단축키" tabindex="-1">VS Code 명령 및 단축키 <a class="header-anchor" href="#vs-code-명령-및-단축키" aria-label="Permalink to &quot;VS Code 명령 및 단축키&quot;">​</a></h2><p>Command Palette(<code>Cmd+Shift+P</code> Mac 또는 <code>Ctrl+Shift+P</code> Windows/Linux)를 열고 &quot;Claude Code&quot;를 입력하면 Claude Code 확장 프로그램에 사용 가능한 모든 VS Code 명령을 볼 수 있습니다.</p><p>일부 단축키는 어떤 패널이 &quot;포커스&quot;되어 있는지(키보드 입력을 받는지)에 따라 달라집니다. 커서가 코드 파일에 있으면 편집기가 포커스됩니다. 커서가 Claude의 프롬프트 박스에 있으면 Claude가 포커스됩니다. <code>Cmd+Esc</code> / <code>Ctrl+Esc</code>를 사용하여 둘 사이를 전환할 수 있습니다.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>이것은 확장 프로그램을 제어하기 위한 VS Code 명령입니다. 모든 내장 Claude Code 명령이 확장 프로그램에서 사용 가능한 것은 아닙니다. 자세한 내용은 <a href="#vs-code-확장-프로그램-vs-claude-code-cli">VS Code 확장 프로그램 vs. Claude Code CLI</a>를 참조하세요.</p></div><table tabindex="0"><thead><tr><th>명령</th><th>단축키</th><th>설명</th></tr></thead><tbody><tr><td>Focus Input</td><td><code>Cmd+Esc</code> (Mac) / <code>Ctrl+Esc</code> (Windows/Linux)</td><td>편집기와 Claude 간 포커스 전환</td></tr><tr><td>Open in Side Bar</td><td>-</td><td>왼쪽 사이드바에서 Claude 열기</td></tr><tr><td>Open in Terminal</td><td>-</td><td>터미널 모드에서 Claude 열기</td></tr><tr><td>Open in New Tab</td><td><code>Cmd+Shift+Esc</code> (Mac) / <code>Ctrl+Shift+Esc</code> (Windows/Linux)</td><td>편집기 탭으로 새 대화 열기</td></tr><tr><td>Open in New Window</td><td>-</td><td>별도 창에서 새 대화 열기</td></tr><tr><td>New Conversation</td><td><code>Cmd+N</code> (Mac) / <code>Ctrl+N</code> (Windows/Linux)</td><td>새 대화 시작. Claude가 포커스되고 <code>enableNewConversationShortcut</code>이 <code>true</code>로 설정되어 있어야 합니다</td></tr><tr><td>Insert @-Mention Reference</td><td><code>Option+K</code> (Mac) / <code>Alt+K</code> (Windows/Linux)</td><td>현재 파일 및 선택 영역에 대한 참조 삽입 (편집기 포커스 필요)</td></tr><tr><td>Show Logs</td><td>-</td><td>확장 프로그램 디버그 로그 보기</td></tr><tr><td>Logout</td><td>-</td><td>Anthropic 계정 로그아웃</td></tr></tbody></table><h3 id="다른-도구에서-vs-code-탭-실행" tabindex="-1">다른 도구에서 VS Code 탭 실행 <a class="header-anchor" href="#다른-도구에서-vs-code-탭-실행" aria-label="Permalink to &quot;다른 도구에서 VS Code 탭 실행&quot;">​</a></h3><p>확장 프로그램은 <code>vscode://anthropic.claude-code/open</code>에 URI 핸들러를 등록합니다. 셸 별칭, 브라우저 북마크릿 또는 URL을 열 수 있는 스크립트와 같은 자체 도구에서 새 Claude Code 탭을 열 때 사용하세요. VS Code가 아직 실행 중이 아니면 URL을 열 때 먼저 실행됩니다. VS Code가 이미 실행 중이면 URL이 현재 포커스된 창에서 열립니다.</p><p>운영 체제의 URL 오프너로 핸들러를 호출합니다. macOS에서:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">open</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;vscode://anthropic.claude-code/open&quot;</span></span></code></pre></div><p>Linux에서는 <code>xdg-open</code>, Windows에서는 <code>start</code>를 사용하세요.</p><p>핸들러는 두 가지 선택적 쿼리 매개변수를 허용합니다:</p><table tabindex="0"><thead><tr><th>매개변수</th><th>설명</th></tr></thead><tbody><tr><td><code>prompt</code></td><td>프롬프트 박스에 미리 채울 텍스트. URL 인코딩이 필요합니다. 프롬프트는 미리 채워지지만 자동으로 전송되지 않습니다.</td></tr><tr><td><code>session</code></td><td>새 대화를 시작하는 대신 재개할 세션 ID. VS Code에서 현재 열린 워크스페이스에 속한 세션이어야 합니다. 세션을 찾을 수 없으면 새 대화가 시작됩니다. 세션이 이미 탭에서 열려 있으면 해당 탭이 포커스됩니다. 세션 ID를 프로그래밍 방식으로 캡처하려면 <a href="/claude-code-docs-ko/headless.html#continue-conversations">대화 계속하기</a>를 참조하세요.</td></tr></tbody></table><p>예를 들어, &quot;review my changes&quot;가 미리 채워진 탭을 열려면:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>vscode://anthropic.claude-code/open?prompt=review%20my%20changes</span></span></code></pre></div><h2 id="설정-구성" tabindex="-1">설정 구성 <a class="header-anchor" href="#설정-구성" aria-label="Permalink to &quot;설정 구성&quot;">​</a></h2><p>확장 프로그램에는 두 가지 유형의 설정이 있습니다:</p><ul><li><strong>VS Code의 확장 프로그램 설정</strong>: VS Code 내에서 확장 프로그램의 동작을 제어합니다. <code>Cmd+,</code> (Mac) 또는 <code>Ctrl+,</code> (Windows/Linux)로 열고 Extensions → Claude Code로 이동합니다. <code>/</code>를 입력하고 <strong>General Config</strong>를 선택하여 설정을 열 수도 있습니다.</li><li><strong><code>~/.claude/settings.json</code>의 Claude Code 설정</strong>: 확장 프로그램과 CLI 간에 공유됩니다. 허용된 명령, 환경 변수, 훅 및 MCP 서버에 사용합니다. 자세한 내용은 <a href="/claude-code-docs-ko/settings.html">설정</a>을 참조하세요.</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p><code>settings.json</code>에 <code>&quot;$schema&quot;: &quot;https://json.schemastore.org/claude-code-settings.json&quot;</code>을 추가하면 VS Code에서 모든 사용 가능한 설정에 대한 자동 완성 및 인라인 유효성 검사를 받을 수 있습니다.</p></div><h3 id="확장-프로그램-설정" tabindex="-1">확장 프로그램 설정 <a class="header-anchor" href="#확장-프로그램-설정" aria-label="Permalink to &quot;확장 프로그램 설정&quot;">​</a></h3><table tabindex="0"><thead><tr><th>설정</th><th>기본값</th><th>설명</th></tr></thead><tbody><tr><td><code>useTerminal</code></td><td><code>false</code></td><td>그래픽 패널 대신 터미널 모드에서 Claude 실행</td></tr><tr><td><code>initialPermissionMode</code></td><td><code>default</code></td><td>새 대화의 승인 프롬프트 제어: <code>default</code>, <code>plan</code>, <code>acceptEdits</code>, 또는 <code>bypassPermissions</code>. <a href="/claude-code-docs-ko/permission-modes.html">권한 모드</a>를 참조하세요.</td></tr><tr><td><code>preferredLocation</code></td><td><code>panel</code></td><td>Claude가 열리는 위치: <code>sidebar</code> (오른쪽) 또는 <code>panel</code> (새 탭)</td></tr><tr><td><code>autosave</code></td><td><code>true</code></td><td>Claude가 파일을 읽거나 쓰기 전에 자동 저장</td></tr><tr><td><code>useCtrlEnterToSend</code></td><td><code>false</code></td><td>Enter 대신 Ctrl/Cmd+Enter를 사용하여 프롬프트 전송</td></tr><tr><td><code>enableNewConversationShortcut</code></td><td><code>false</code></td><td>Cmd/Ctrl+N으로 새 대화 시작 활성화</td></tr><tr><td><code>hideOnboarding</code></td><td><code>false</code></td><td>온보딩 체크리스트 숨기기 (졸업모자 아이콘)</td></tr><tr><td><code>respectGitIgnore</code></td><td><code>true</code></td><td>파일 검색에서 .gitignore 패턴 제외</td></tr><tr><td><code>usePythonEnvironment</code></td><td><code>true</code></td><td>Claude 실행 시 워크스페이스의 Python 환경 활성화. Python 확장 프로그램이 필요합니다.</td></tr><tr><td><code>environmentVariables</code></td><td><code>[]</code></td><td>Claude 프로세스의 환경 변수 설정. 공유 구성에는 Claude Code 설정을 사용하세요.</td></tr><tr><td><code>disableLoginPrompt</code></td><td><code>false</code></td><td>인증 프롬프트 건너뜀 (서드파티 공급자 설정용)</td></tr><tr><td><code>allowDangerouslySkipPermissions</code></td><td><code>false</code></td><td>모드 선택기에 <a href="/claude-code-docs-ko/permission-modes.html#eliminate-prompts-with-auto-mode">Auto 모드</a>와 권한 우회를 추가합니다. Auto 모드에는 <a href="/claude-code-docs-ko/permission-modes.html#eliminate-prompts-with-auto-mode">플랜, 관리자, 모델 및 공급자 요구 사항</a>이 있으므로 이 토글을 켜도 사용 불가능할 수 있습니다. 인터넷 액세스 없는 샌드박스에서만 권한 우회를 사용하세요.</td></tr><tr><td><code>claudeProcessWrapper</code></td><td>-</td><td>Claude 프로세스를 시작하는 데 사용되는 실행 파일 경로</td></tr></tbody></table><h2 id="vs-code-확장-프로그램-vs-claude-code-cli" tabindex="-1">VS Code 확장 프로그램 vs. Claude Code CLI <a class="header-anchor" href="#vs-code-확장-프로그램-vs-claude-code-cli" aria-label="Permalink to &quot;VS Code 확장 프로그램 vs. Claude Code CLI&quot;">​</a></h2><p>Claude Code는 VS Code 확장 프로그램(그래픽 패널)과 CLI(터미널의 명령줄 인터페이스) 모두로 사용할 수 있습니다. 일부 기능은 CLI에서만 사용할 수 있습니다. CLI 전용 기능이 필요하면 VS Code의 통합 터미널에서 <code>claude</code>를 실행하세요.</p><table tabindex="0"><thead><tr><th>기능</th><th>CLI</th><th>VS Code 확장 프로그램</th></tr></thead><tbody><tr><td>명령 및 스킬</td><td><a href="/claude-code-docs-ko/commands.html">모두</a></td><td>일부 (<code>/</code>를 입력하여 사용 가능한 항목 확인)</td></tr><tr><td>MCP 서버 구성</td><td>예</td><td>부분 (CLI로 서버 추가; 채팅 패널에서 <code>/mcp</code>로 기존 서버 관리)</td></tr><tr><td>체크포인트</td><td>예</td><td>예</td></tr><tr><td><code>!</code> bash 단축키</td><td>예</td><td>아니오</td></tr><tr><td>탭 완성</td><td>예</td><td>아니오</td></tr></tbody></table><h3 id="체크포인트로-되돌리기" tabindex="-1">체크포인트로 되돌리기 <a class="header-anchor" href="#체크포인트로-되돌리기" aria-label="Permalink to &quot;체크포인트로 되돌리기&quot;">​</a></h3><p>VS Code 확장 프로그램은 Claude의 파일 편집을 추적하고 이전 상태로 되돌릴 수 있는 체크포인트를 지원합니다. 메시지 위에 마우스를 올려 되돌리기 버튼을 표시하고 세 가지 옵션 중 하나를 선택하세요:</p><ul><li><strong>Fork conversation from here</strong>: 모든 코드 변경 사항을 유지하면서 이 메시지에서 새 대화 분기 시작</li><li><strong>Rewind code to here</strong>: 전체 대화 기록을 유지하면서 대화의 이 시점으로 파일 변경 사항 되돌리기</li><li><strong>Fork conversation and rewind code</strong>: 새 대화 분기를 시작하고 파일 변경 사항을 이 시점으로 되돌리기</li></ul><p>체크포인트의 작동 방식과 제한 사항에 대한 자세한 내용은 <a href="/claude-code-docs-ko/checkpointing.html">체크포인팅</a>을 참조하세요.</p><h3 id="vs-code에서-cli-실행" tabindex="-1">VS Code에서 CLI 실행 <a class="header-anchor" href="#vs-code에서-cli-실행" aria-label="Permalink to &quot;VS Code에서 CLI 실행&quot;">​</a></h3><p>VS Code에서 머물면서 CLI를 사용하려면 통합 터미널(Windows/Linux의 경우 <code>Ctrl+`</code>, Mac의 경우 <code>Cmd+`</code>)을 열고 <code>claude</code>를 실행하세요. CLI는 diff 보기 및 진단 공유와 같은 기능을 위해 IDE와 자동으로 통합됩니다.</p><p>외부 터미널을 사용하는 경우 Claude Code 내에서 <code>/ide</code>를 실행하여 VS Code에 연결하세요.</p><h3 id="확장-프로그램과-cli-간-전환" tabindex="-1">확장 프로그램과 CLI 간 전환 <a class="header-anchor" href="#확장-프로그램과-cli-간-전환" aria-label="Permalink to &quot;확장 프로그램과 CLI 간 전환&quot;">​</a></h3><p>확장 프로그램과 CLI는 동일한 대화 기록을 공유합니다. 확장 프로그램 대화를 CLI에서 계속하려면 터미널에서 <code>claude --resume</code>을 실행하세요. 그러면 대화를 검색하고 선택할 수 있는 인터랙티브 선택기가 열립니다.</p><h3 id="프롬프트에-터미널-출력-포함" tabindex="-1">프롬프트에 터미널 출력 포함 <a class="header-anchor" href="#프롬프트에-터미널-출력-포함" aria-label="Permalink to &quot;프롬프트에 터미널 출력 포함&quot;">​</a></h3><p><code>@terminal:name</code>을 사용하여 프롬프트에서 터미널 출력을 참조하세요. 여기서 <code>name</code>은 터미널의 제목입니다. 이렇게 하면 Claude가 복사-붙여넣기 없이 명령 출력, 오류 메시지 또는 로그를 볼 수 있습니다.</p><h3 id="백그라운드-프로세스-모니터링" tabindex="-1">백그라운드 프로세스 모니터링 <a class="header-anchor" href="#백그라운드-프로세스-모니터링" aria-label="Permalink to &quot;백그라운드 프로세스 모니터링&quot;">​</a></h3><p>Claude가 장시간 실행되는 명령을 실행하면 확장 프로그램이 상태 표시줄에 진행 상황을 표시합니다. 그러나 백그라운드 작업의 가시성은 CLI에 비해 제한적입니다. 더 나은 가시성을 위해 Claude에게 명령을 출력하도록 요청하여 VS Code의 통합 터미널에서 실행할 수 있습니다.</p><h3 id="mcp로-외부-도구-연결" tabindex="-1">MCP로 외부 도구 연결 <a class="header-anchor" href="#mcp로-외부-도구-연결" aria-label="Permalink to &quot;MCP로 외부 도구 연결&quot;">​</a></h3><p>MCP (Model Context Protocol) 서버는 Claude에게 외부 도구, 데이터베이스 및 API에 대한 액세스를 제공합니다.</p><p>MCP 서버를 추가하려면 통합 터미널(<code>Ctrl+`</code> 또는 <code>Cmd+`</code>)을 열고 다음을 실행하세요:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mcp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --transport</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> github</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://api.githubcopilot.com/mcp/</span></span></code></pre></div><p>구성 후 Claude에게 도구 사용을 요청합니다(예: &quot;Review PR #456&quot;).</p><p>VS Code를 떠나지 않고 MCP 서버를 관리하려면 채팅 패널에 <code>/mcp</code>를 입력하세요. MCP 관리 대화 상자에서 서버를 활성화하거나 비활성화하고, 서버에 다시 연결하고, OAuth 인증을 관리할 수 있습니다. 사용 가능한 서버는 <a href="/claude-code-docs-ko/mcp.html">MCP 설명서</a>를 참조하세요.</p><h2 id="git으로-작업하기" tabindex="-1">git으로 작업하기 <a class="header-anchor" href="#git으로-작업하기" aria-label="Permalink to &quot;git으로 작업하기&quot;">​</a></h2><p>Claude Code는 git과 통합되어 VS Code에서 직접 버전 제어 워크플로우를 지원합니다. Claude에게 변경 사항 커밋, 풀 리퀘스트 생성 또는 브랜치 간 작업을 요청하세요.</p><h3 id="커밋-및-풀-리퀘스트-생성" tabindex="-1">커밋 및 풀 리퀘스트 생성 <a class="header-anchor" href="#커밋-및-풀-리퀘스트-생성" aria-label="Permalink to &quot;커밋 및 풀 리퀘스트 생성&quot;">​</a></h3><p>Claude는 변경 사항 스테이징, 커밋 메시지 작성 및 작업을 기반으로 풀 리퀘스트를 생성할 수 있습니다:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt; commit my changes with a descriptive message</span></span>\n<span class="line"><span>&gt; create a pr for this feature</span></span>\n<span class="line"><span>&gt; summarize the changes I&#39;ve made to the auth module</span></span></code></pre></div><p>풀 리퀘스트를 생성할 때 Claude는 실제 코드 변경 사항을 기반으로 설명을 생성하고 테스트 또는 구현 결정에 대한 컨텍스트를 추가할 수 있습니다.</p><h3 id="병렬-작업에-git-worktree-사용" tabindex="-1">병렬 작업에 git worktree 사용 <a class="header-anchor" href="#병렬-작업에-git-worktree-사용" aria-label="Permalink to &quot;병렬 작업에 git worktree 사용&quot;">​</a></h3><p><code>--worktree</code> (<code>-w</code>) 플래그를 사용하여 자체 파일과 브랜치가 있는 격리된 worktree에서 Claude를 시작하세요:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --worktree</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> feature-auth</span></span></code></pre></div><p>각 worktree는 git 히스토리를 공유하면서 독립적인 파일 상태를 유지합니다. 이렇게 하면 다른 작업을 할 때 Claude 인스턴스들이 서로 방해하지 않습니다. 자세한 내용은 <a href="/claude-code-docs-ko/common-workflows.html#run-parallel-claude-code-sessions-with-git-worktrees">Git worktree로 병렬 세션 실행하기</a>를 참조하세요.</p><h2 id="서드파티-공급자-사용" tabindex="-1">서드파티 공급자 사용 <a class="header-anchor" href="#서드파티-공급자-사용" aria-label="Permalink to &quot;서드파티 공급자 사용&quot;">​</a></h2><p>기본적으로 Claude Code는 Anthropic의 API에 직접 연결합니다. 조직에서 Amazon Bedrock, Google Vertex AI 또는 Microsoft Foundry를 사용하여 Claude에 액세스하는 경우 대신 공급자를 사용하도록 확장 프로그램을 구성하세요:</p><p><strong>1단계: 로그인 프롬프트 비활성화</strong></p><p><a href="vscode://settings/claudeCode.disableLoginPrompt" target="_blank" rel="noreferrer">Disable Login Prompt 설정</a>을 열고 체크박스를 선택합니다.</p><p>VS Code 설정(<code>Cmd+,</code> Mac 또는 <code>Ctrl+,</code> Windows/Linux)을 열고 &quot;Claude Code login&quot;을 검색하여 <strong>Disable Login Prompt</strong>를 체크할 수도 있습니다.</p><p><strong>2단계: 공급자 구성</strong></p><p>공급자의 설정 가이드를 따르세요:</p><ul><li><a href="/claude-code-docs-ko/amazon-bedrock.html">Amazon Bedrock의 Claude Code</a></li><li><a href="/claude-code-docs-ko/google-vertex-ai.html">Google Vertex AI의 Claude Code</a></li><li><a href="/claude-code-docs-ko/microsoft-foundry.html">Microsoft Foundry의 Claude Code</a></li></ul><p>이 가이드에서는 <code>~/.claude/settings.json</code>에 공급자를 구성하는 방법을 다루며, VS Code 확장 프로그램과 CLI 간에 설정이 공유됩니다.</p><h2 id="보안-및-개인-정보-보호" tabindex="-1">보안 및 개인 정보 보호 <a class="header-anchor" href="#보안-및-개인-정보-보호" aria-label="Permalink to &quot;보안 및 개인 정보 보호&quot;">​</a></h2><p>코드는 비공개로 유지됩니다. Claude Code는 지원을 제공하기 위해 코드를 처리하지만 모델 학습에 사용하지 않습니다. 데이터 처리 및 로깅 옵트아웃 방법에 대한 자세한 내용은 <a href="/claude-code-docs-ko/data-usage.html">데이터 및 개인 정보 보호</a>를 참조하세요.</p><p>자동 편집 권한이 활성화된 경우 Claude Code는 VS Code가 자동으로 실행할 수 있는 VS Code 구성 파일(예: <code>settings.json</code> 또는 <code>tasks.json</code>)을 수정할 수 있습니다. 신뢰할 수 없는 코드를 다룰 때 위험을 줄이려면:</p><ul><li>신뢰할 수 없는 워크스페이스에 <a href="https://code.visualstudio.com/docs/editor/workspace-trust#_restricted-mode" target="_blank" rel="noreferrer">VS Code 제한 모드</a> 활성화</li><li>자동 수락 대신 수동 승인 모드 사용</li><li>수락하기 전에 변경 사항을 주의 깊게 검토</li></ul><h3 id="내장-ide-mcp-서버" tabindex="-1">내장 IDE MCP 서버 <a class="header-anchor" href="#내장-ide-mcp-서버" aria-label="Permalink to &quot;내장 IDE MCP 서버&quot;">​</a></h3><p>확장 프로그램이 활성화되면 CLI가 자동으로 연결하는 로컬 MCP 서버를 실행합니다. 이것이 CLI가 VS Code의 기본 diff 뷰어에서 diff를 열고, <code>@</code>-멘션을 위한 현재 선택 영역을 읽고, Jupyter 노트북에서 작업할 때 VS Code에 셀을 실행하도록 요청하는 방법입니다.</p><p>서버는 <code>ide</code>라는 이름으로 구성할 것이 없기 때문에 <code>/mcp</code>에서 숨겨져 있습니다. 그러나 조직에서 MCP 도구를 허용 목록에 추가하기 위해 <code>PreToolUse</code> 훅을 사용하는 경우 존재를 알아야 합니다.</p><p><strong>전송 및 인증.</strong> 서버는 임의의 높은 포트에서 <code>127.0.0.1</code>에 바인딩되며 다른 컴퓨터에서는 접근할 수 없습니다. 각 확장 프로그램 활성화 시 CLI가 연결에 제공해야 하는 새로운 임의 인증 토큰이 생성됩니다. 토큰은 <code>0700</code> 디렉토리의 <code>0600</code> 권한으로 <code>~/.claude/ide/</code> 아래의 잠금 파일에 기록되므로 VS Code를 실행하는 사용자만 읽을 수 있습니다.</p><p><strong>모델에 노출되는 도구.</strong> 서버는 수십 가지 도구를 호스팅하지만 모델에는 두 가지만 표시됩니다. 나머지는 CLI가 자체 UI에 사용하는 내부 RPC(diff 열기, 선택 읽기, 파일 저장)로 도구 목록이 Claude에 도달하기 전에 필터링됩니다.</p><table tabindex="0"><thead><tr><th>도구 이름 (훅에서 표시되는 이름)</th><th>기능</th><th>쓰기 여부</th></tr></thead><tbody><tr><td><code>mcp__ide__getDiagnostics</code></td><td>VS Code의 Problems 패널에 있는 언어 서버 진단(오류 및 경고)을 반환합니다. 선택적으로 하나의 파일로 범위를 지정할 수 있습니다.</td><td>아니오</td></tr><tr><td><code>mcp__ide__executeCode</code></td><td>활성 Jupyter 노트북의 커널에서 Python 코드를 실행합니다. 아래의 확인 흐름을 참조하세요.</td><td>예</td></tr></tbody></table><p><strong>Jupyter 실행은 항상 먼저 확인합니다.</strong> <code>mcp__ide__executeCode</code>는 자동으로 실행할 수 없습니다. 각 호출 시 코드가 활성 노트북 끝에 새 셀로 삽입되고 VS Code가 이를 보이게 스크롤하며, 기본 Quick Pick이 <strong>Execute</strong> 또는 <strong>Cancel</strong>을 묻습니다. <code>Esc</code>로 취소하거나 선택기를 닫으면 Claude에게 오류가 반환되고 아무것도 실행되지 않습니다. 이 도구는 활성 노트북이 없거나, Jupyter 확장 프로그램(<code>ms-toolsai.jupyter</code>)이 설치되어 있지 않거나, 커널이 Python이 아닌 경우에도 완전히 거부합니다.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Quick Pick 확인은 <code>PreToolUse</code> 훅과 별개입니다. <code>mcp__ide__executeCode</code>에 대한 허용 목록 항목은 Claude가 셀 실행을 <em>제안</em>할 수 있게 합니다. VS Code 내의 Quick Pick이 실제로 <em>실행</em>할 수 있게 합니다.</p></div><a id="troubleshooting"></a><h2 id="일반적인-문제-해결" tabindex="-1">일반적인 문제 해결 <a class="header-anchor" href="#일반적인-문제-해결" aria-label="Permalink to &quot;일반적인 문제 해결&quot;">​</a></h2><h3 id="확장-프로그램-설치-불가" tabindex="-1">확장 프로그램 설치 불가 <a class="header-anchor" href="#확장-프로그램-설치-불가" aria-label="Permalink to &quot;확장 프로그램 설치 불가&quot;">​</a></h3><ul><li>VS Code의 호환 가능한 버전(1.98.0 이상)이 있는지 확인하세요</li><li>VS Code에 확장 프로그램을 설치할 권한이 있는지 확인하세요</li><li><a href="https://marketplace.visualstudio.com/items?itemName=anthropic.claude-code" target="_blank" rel="noreferrer">VS Code Marketplace</a>에서 직접 설치해 보세요</li></ul><h3 id="spark-아이콘이-보이지-않음" tabindex="-1">Spark 아이콘이 보이지 않음 <a class="header-anchor" href="#spark-아이콘이-보이지-않음" aria-label="Permalink to &quot;Spark 아이콘이 보이지 않음&quot;">​</a></h3><p>Spark 아이콘은 파일이 열려 있을 때 <strong>편집기 도구 모음</strong>(편집기 오른쪽 상단)에 나타납니다. 표시되지 않는 경우:</p><ol><li><strong>파일 열기</strong>: 아이콘은 파일이 열려 있어야 합니다. 폴더만 열려 있는 것으로는 충분하지 않습니다.</li><li><strong>VS Code 버전 확인</strong>: 1.98.0 이상이 필요합니다 (Help → About)</li><li><strong>VS Code 다시 시작</strong>: Command Palette에서 &quot;Developer: Reload Window&quot; 실행</li><li><strong>충돌하는 확장 프로그램 비활성화</strong>: 다른 AI 확장 프로그램(Cline, Continue 등)을 일시적으로 비활성화</li><li><strong>워크스페이스 신뢰 확인</strong>: 확장 프로그램은 제한 모드에서 작동하지 않습니다</li></ol><p>또는 <strong>Status Bar</strong>(오른쪽 하단)에서 &quot;✱ Claude Code&quot;를 클릭하세요. 파일 없이도 작동합니다. <strong>Command Palette</strong>(<code>Cmd+Shift+P</code> / <code>Ctrl+Shift+P</code>)를 사용하고 &quot;Claude Code&quot;를 입력할 수도 있습니다.</p><h3 id="claude-code가-응답하지-않음" tabindex="-1">Claude Code가 응답하지 않음 <a class="header-anchor" href="#claude-code가-응답하지-않음" aria-label="Permalink to &quot;Claude Code가 응답하지 않음&quot;">​</a></h3><p>Claude Code가 프롬프트에 응답하지 않는 경우:</p><ol><li><strong>인터넷 연결 확인</strong>: 안정적인 인터넷 연결이 있는지 확인</li><li><strong>새 대화 시작</strong>: 새 대화를 시작하여 문제가 지속되는지 확인</li><li><strong>CLI 시도</strong>: 터미널에서 <code>claude</code>를 실행하여 더 자세한 오류 메시지 확인</li></ol><p>문제가 지속되면 오류에 대한 자세한 내용과 함께 <a href="https://github.com/anthropics/claude-code/issues" target="_blank" rel="noreferrer">GitHub에 이슈를 제출</a>하세요.</p><h2 id="확장-프로그램-제거" tabindex="-1">확장 프로그램 제거 <a class="header-anchor" href="#확장-프로그램-제거" aria-label="Permalink to &quot;확장 프로그램 제거&quot;">​</a></h2><p>Claude Code 확장 프로그램을 제거하려면:</p><ol><li>확장 프로그램 보기 열기 (<code>Cmd+Shift+X</code> Mac 또는 <code>Ctrl+Shift+X</code> Windows/Linux)</li><li>&quot;Claude Code&quot; 검색</li><li><strong>제거</strong> 클릭</li></ol><p>확장 프로그램 데이터를 제거하고 모든 설정을 초기화하려면:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -rf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.vscode/globalStorage/anthropic.claude-code</span></span></code></pre></div><p>추가 도움이 필요하면 <a href="/claude-code-docs-ko/troubleshooting.html">문제 해결 가이드</a>를 참조하세요.</p><h2 id="다음-단계" tabindex="-1">다음 단계 <a class="header-anchor" href="#다음-단계" aria-label="Permalink to &quot;다음 단계&quot;">​</a></h2><p>VS Code에서 Claude Code를 설정했으니:</p><ul><li><a href="/claude-code-docs-ko/common-workflows.html">일반 워크플로우 탐색하기</a>로 Claude Code를 최대한 활용하세요</li><li><a href="/claude-code-docs-ko/mcp.html">MCP 서버 설정하기</a>로 외부 도구로 Claude의 기능을 확장하세요. CLI로 서버를 추가한 다음 채팅 패널에서 <code>/mcp</code>로 관리하세요.</li><li><a href="/claude-code-docs-ko/settings.html">Claude Code 설정 구성하기</a>로 허용된 명령, 훅 등을 사용자 정의하세요. 이러한 설정은 확장 프로그램과 CLI 간에 공유됩니다.</li></ul>',184)])])}const C=o(l,[["render",s]]);export{u as __pageData,C as default};
